using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private MulticlassClassificationMetrics? _metrics;
    private VBuffer<ReadOnlyMemory<char>> _labelBuffer;

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
    }

    public MulticlassClassificationMetrics TrainAndEvaluate()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label")
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Use cross-validation for evaluation since dataset is small
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(dataView, pipeline, numberOfFolds: 3);
        _metrics = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First().Metrics;

        // Train final model on all data
        var model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(model);

        // Extract label names for confidence mapping
        var transformer = model.LastTransformer.Model;
        var labelColumn = model.GetOutputSchema(dataView.Schema)["PredictedLabel"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        model.GetOutputSchema(dataView.Schema)["Score"].GetSlotNames(ref slotNames);
        _labelBuffer = slotNames;

        return _metrics;
    }

    public MulticlassClassificationMetrics GetMetrics()
    {
        return _metrics ?? throw new InvalidOperationException("Model has not been trained yet.");
    }

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        if (_predictionEngine is null)
            throw new InvalidOperationException("Model has not been trained yet.");

        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var labels = _labelBuffer.DenseValues().Select(l => l.ToString()).ToArray();
        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[labels[i]] = prediction.Score[i];
        }

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }
}

